Here's a modern MSTest approach covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // MSTest natively awaits async Task test methods — no .Result or .GetAwaiter() needed.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Use [Timeout] (milliseconds) to fail-fast on hangs.
    // MSTest v3+ flows a CancellationToken via TestContext.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_ThrowsOnFailure()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Testing that your code honours cancellation tokens:
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        var handler = new FakeHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no Moq needed for HttpClient
    private sealed class FakeHandler(string content, HttpStatusCode status, TimeSpan? delay = null)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay is { } d)
                await Task.Delay(d, cancellationToken);

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Detail |
|---|---|
| **`async Task` methods** | MSTest awaits them natively — never use `async void` |
| **`[Timeout(ms)]`** | Fails the test if it hangs; in MSTest v3+ this cancels the token from `TestContext` |
| **`Assert.ThrowsExceptionAsync<T>`** | Proper async exception assertion (not `ThrowsException`) |
| **Cancellation testing** | Pre-cancel a `CancellationTokenSource`, then verify `TaskCanceledException` is thrown |
| **`HttpMessageHandler` fake** | Avoids mocking `HttpClient` directly (which doesn't work well) — inject a custom handler instead |

> **MSTest v3+ tip:** If you add `TestContext` as a property, `TestContext.CancellationTokenSource` gives you the token tied to `[Timeout]`, so your SUT can react to test-framework-driven cancellation too.
